sp_angular_provider.script:
function scmTableOrchestrationService(scmTableDataService) {
    "use strict";

    function createInitialState() {
        return {
            totalRecords: 0,
            totalPages: 0,
            page: 1,
            records: [],
            fieldToAdd: null,
            fieldToRemove: null,
        };
    }

    function getFirstPage() {
        return 1;
    }

    function getPreviousPage(currentPage) {
        return currentPage > 1 ? currentPage - 1 : currentPage;
    }

    function getNextPage(currentPage, totalPages) {
        return currentPage < totalPages ? currentPage + 1 : currentPage;
    }

    function getLastPage(totalPages) {
        return totalPages || 1;
    }

    function computeTotalPages(totalRecords, limit) {
        return scmTableDataService.computeTotalPages(totalRecords, limit);
    }

    function refreshTableData(options) {
        options = options || {};

        var requestId = scmTableDataService.nextRequestId(
            options.currentRequestId,
        );

        if (typeof options.setRequestId === "function") {
            options.setRequestId(requestId);
        }

        if (typeof options.setLoading === "function") {
            options.setLoading(true);
        }

        return scmTableDataService
            .getTableData({
                server: options.server,
                transactionId: options.transactionId,
                tableProviderScriptInclude: options.tableProviderScriptInclude,
                page: options.page,
                filters: options.filters || [],
                includeTotalRecords: !!options.includeTotalRecords,
            })
            .then(function (response) {
                var latestRequestId =
                    typeof options.getCurrentRequestId === "function"
                        ? options.getCurrentRequestId()
                        : requestId;

                if (
                    !scmTableDataService.isLatestRequest(
                        requestId,
                        latestRequestId,
                    )
                ) {
                    return { stale: true, requestId: requestId };
                }

                var responseData = (response && response.data) || {};
                var result = {
                    stale: false,
                    requestId: requestId,
                    records: responseData.records || [],
                    orderBy: responseData.orderBy,
                    orderDirection: responseData.orderDirection,
                    totalRecords: responseData.totalRecords,
                    includeTotalRecords: !!options.includeTotalRecords,
                };

                if (typeof options.onSuccess === "function") {
                    options.onSuccess(result);
                }

                return result;
            })
            .catch(function (error) {
                var latestRequestId =
                    typeof options.getCurrentRequestId === "function"
                        ? options.getCurrentRequestId()
                        : requestId;

                if (
                    !scmTableDataService.isLatestRequest(
                        requestId,
                        latestRequestId,
                    )
                ) {
                    return { stale: true, requestId: requestId };
                }

                if (typeof options.onError === "function") {
                    options.onError(error);
                }

                return { stale: false, requestId: requestId, error: error };
            })
            .finally(function () {
                var latestRequestId =
                    typeof options.getCurrentRequestId === "function"
                        ? options.getCurrentRequestId()
                        : requestId;

                if (
                    scmTableDataService.isLatestRequest(
                        requestId,
                        latestRequestId,
                    ) &&
                    typeof options.setLoading === "function"
                ) {
                    options.setLoading(false);
                }
            });
    }

    return {
        createInitialState: createInitialState,
        getFirstPage: getFirstPage,
        getPreviousPage: getPreviousPage,
        getNextPage: getNextPage,
        getLastPage: getLastPage,
        computeTotalPages: computeTotalPages,
        refreshTableData: refreshTableData,
    };
}
